# schema.graphqls — Flipkart Product Catalog

scalar Long

type Product {
  id: ID!
  name: String!
  price: Price!
  category: Category!
  description: String          # nullable: not all products have descriptions
  reviews: [Review!]!
  inStock: Boolean!
  sellerId: ID!
}

type Price {
  amount: Float!
  currency: String!            # 'INR'
  discountedAmount: Float      # nullable: no discount if not on sale
}

type Review {
  id: ID!
  rating: Int!                 # 1-5
  comment: String
  authorName: String!
  createdAt: String!           # ISO date string
}

enum Category {
  ELECTRONICS
  CLOTHING
  BOOKS
  HOME_KITCHEN
  SPORTS
}

input CreateProductInput {
  name: String!
  priceAmount: Float!
  category: Category!
  description: String           # optional
  sellerId: ID!
}

input AddReviewInput {
  rating: Int!                  # 1-5
  comment: String
  authorName: String!
}

type Query {
  product(id: ID!): Product     # nullable: returns null if not found
  products(category: Category): [Product!]!
  searchProducts(keyword: String!): [Product!]!
}

type Mutation {
  createProduct(input: CreateProductInput!): Product!
  addReview(productId: ID!, input: AddReviewInput!): Review!
  deleteProduct(id: ID!): Boolean!
}

# 1. Single product — fetch exactly the fields needed:
query GetProductPage($id: ID!) {
  product(id: $id) {
    id
    name
    price {
      amount
      currency
      discountedAmount   # nullable: could be null if no discount
    }
    reviews {
      rating
      comment            # nullable: review might have no comment
      authorName
    }
    category
    inStock
  }
}
# Variables: { "id": "PROD-001" }

