      discountedAmount
    }
    inStock
    # NOT fetching reviews (not needed on list page = no N+1)
  }
}

# 3. Search query with variables:
query SearchLaptops($keyword: String!) {
  searchProducts(keyword: $keyword) {
    id
    name
    price {
      amount
      discountedAmount
    }
    category
  }
}
# Variables: { "keyword": "laptop" }

# 4. Create product mutation:
mutation AddFlipkartProduct($input: CreateProductInput!) {
  createProduct(input: $input) {
    id              # fetch the new product's ID after creation
    name
    price { amount }
    category
  }
}
# Variables:
# { "input": {
#   "name": "Samsung Galaxy S24",
#   "priceAmount": 74999.0,
#   "category": "ELECTRONICS",
#   "sellerId": "SELL-001"
# }}

# NULLABLE FIELDS IN RESULTS:
#   product(...) → Product  (query return: nullable if not found)
#   price.discountedAmount → Float  (nullable: no discount = null, not error)
#   review.comment → String  (nullable: review without comment text is valid)

// GraphQL error examples and handling:

// 1. Field not found:
// Query: { product(id: "P1") { nonExistentField } }
// Error: { "errors": [{ "message": "Field 'nonExistentField' in type 'Product' is undefined",
//                       "locations": [{"line": 1, "column": 25}] }] }
// Result: request rejected entirely (validation error before execution)

// 2. Null for non-null field:
// Schema: name: String! (non-null)
// Resolver returns: null  ← runtime error
// GraphQL: propagates null upward — if parent is also non-null, error bubbles
// Error: { "errors": [{ "message": "Cannot return null for non-nullable type: 'String' within parent 'Product' (/product/name)" }],
//           "data": { "product": null } }  ← partial null propagation

// 3. Variable type mismatch:
// Schema: product(id: ID!)
// Query: query($id: String!) { product(id: $id) }  ← ID! not String!
// Actually this works: String can be coerced to ID
// But: Float! arg with String variable: error at validation

// 4. PARTIAL SUCCESS (GraphQL unique feature!):
// Query: { product(id: "P1") { name reviews { comment } } }
// name resolver: succeeds → 'iPhone 15'
// reviews resolver: throws RuntimeException → error
// Response: {
//   "data": { "product": { "name": "iPhone 15", "reviews": null } },  ← partial
//   "errors": [{ "message": "Error fetching reviews", "path": ["product", "reviews"] }]
// }
// Key: data AND errors can coexist in GraphQL!
// REST would return 500 for any resolver failure

import org.springframework.boot.test.context.SpringBootTest;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@SpringBootTest
class GraphQlErrorTest {
    @Test void partialSuccess_conceptDocumented() {
        // GraphQL: errors array coexists with partial data
        // Each error has: message, locations, path (which field failed)
        // Clients must check both data AND errors
        String errorFormat = "{data: {...partial...}, errors: [{message, path}]}";
        assertNotNull(errorFormat);
        System.out.println("GraphQL partial success: data + errors in same response");
    }
    @Test void nonNullViolation_propagates() {
        // Non-null field returning null → error propagates up the tree
        // If product.name: String! returns null:
        //   → product becomes null (non-null parent propagates)
        //   → { data: { product: null }, errors: [{...}] }
        assertTrue(true);
    }
}

# Zerodha Portfolio GraphQL Schema

