  positions: [Position!]!
  lastUpdatedAt: String!    # ISO timestamp
}

type Position {
  symbol: String!           # 'RELIANCE', 'TCS'
  quantity: Int!
  averagePrice: Float!
  currentPrice: Float!
  investedValue: Float!     # quantity × averagePrice
  currentValue: Float!      # quantity × currentPrice
  pnl: Float!               # currentValue - investedValue
  pnlPct: Float!            # pnl / investedValue × 100
}

type TradeHistoryEntry {
  id: ID!
  symbol: String!
  quantity: Int!
  price: Float!
  tradeType: TradeType!
