# Introspection: GraphQL allows clients to query the schema itself
# Available in all GraphQL servers (can be disabled in production for security)

# 1. List all types in the schema:
query ListAllTypes {
  __schema {
    types {
      name
      kind             # OBJECT, SCALAR, ENUM, INPUT_OBJECT, INTERFACE, UNION
      description
    }
  }
}

# 2. Get all fields on a specific type:
query ProductTypeFields {
  __type(name: "Product") {
    name
    fields {
      name
      type {
        name
        kind
        ofType { name kind }  # for List and NonNull wrappers
      }
      isDeprecated
      deprecationReason
    }
  }
}

# 3. Get all available queries:
query ListAvailableQueries {
  __schema {
    queryType {
      fields {
        name
        description
        args {
          name
          type { name }
        }
      }
    }
  }
}

# 4. Check deprecation on a specific field:
query CheckDeprecation {
  __type(name: "Product") {
    fields(includeDeprecated: true) {
      name
      isDeprecated
      deprecationReason
    }
  }
}

# WHY INTROSPECTION MATTERS:
# - GraphQL Playground/Sandbox uses __schema to show autocomplete
# - Code generators (graphql-codegen) use __schema to generate TypeScript types
# - API discovery: clients can find available queries without reading docs
# SECURITY: disable introspection in production (exposes full API surface)
#   spring.graphql.schema.introspection.enabled=false

import org.springframework.boot.test.context.SpringBootTest;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@SpringBootTest
class IntrospectionTest {
    @Test void introspection_conceptDocumented() {
        // __schema: query the schema itself
        // __type(name): inspect a specific type's fields
        // Used by: GraphQL Playground, code generators, API clients
        System.out.println("GraphQL introspection: __schema and __type are built-in queries");
        assertTrue(true);
    }
}

# Schema Evolution — What's Safe vs Breaking

# SAFE CHANGES (backwards compatible):

# 1. Adding a new optional field:
type Product {
  id: ID!
  name: String!
  # New fields added later — clients that don't request them are unaffected:
  rating: Float           # SAFE: nullable new field
  reviewCount: Int        # SAFE: nullable new field
}

# 2. Adding a new query/mutation:
type Query {
  product(id: ID!): Product
  # New query added later:
  featuredProducts: [Product!]!  # SAFE: doesn't break existing queries
}

# 3. @deprecated directive (soft removal):
type Product {
  id: ID!
  name: String!
  price: Float! @deprecated(reason: "Use priceDetails { amount } instead")
  priceDetails: Price!   # New replacement field
}

# BREAKING CHANGES (require client migration):

# 4. BREAKING: removing a field
#   Before: type Product { id, name, price }
#   After:  type Product { id, name }  ← clients querying 'price' now error
#   Solution: deprecate first, wait for clients to migrate, then remove

# 5. BREAKING: renaming a field
#   Before: type Product { name: String! }
#   After:  type Product { productName: String! }  ← 'name' queries fail
#   Solution: keep both, deprecate old, clients migrate to new

# 6. BREAKING: making nullable field non-null
#   Before: description: String    (nullable)
#   After:  description: String!   (non-null) ← clients get null propagation if description is null
#   Solution: don't do this without ensuring resolver always returns non-null

# 7. BREAKING: adding required argument to existing query
#   Before: products: [Product!]!
#   After:  products(category: Category!): [Product!]!  ← existing calls fail (missing required arg)
#   Solution: make new arg optional with default: products(category: Category): [Product!]!

import org.springframework.boot.test.context.SpringBootTest;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@SpringBootTest
class SchemaEvolutionTest {
    @Test void safeChanges_documented() {
        // Safe: add nullable fields, add new queries/mutations, deprecate
        // Breaking: remove fields, rename fields, add required args, nullable→non-null
        System.out.println("GraphQL schema evolution: add fields safely, deprecate before removing");
        assertTrue(true);
    }
    @Test void deprecation_workflow() {
        // @deprecated(reason='...') → tools show warning to clients
        // Clients: continue using deprecated field, plan migration
        // After all clients migrated: remove the field (coordinate with teams)
        assertNotNull("@deprecated directive");
    }
}

# GraphQL Fragments — reusable field selection sets

# Fragment definition:
fragment MenuItemFields on MenuItem {
  id
  name
  price
  vegetarian
  available
  description
}

fragment RestaurantBasicInfo on Restaurant {
  id
  name
  rating
  deliveryTimeMinutes
  deliveryFee
  cuisineType
}

# Usage in queries — spread with '...':
query SwiggyHomePage {
  nearbyRestaurants(lat: 17.385, lng: 78.487, limit: 10) {
    ...RestaurantBasicInfo    # spread the fragment
    # Only basic info needed on home page (no menu)
  }
}

query RestaurantMenu($restaurantId: ID!) {
  restaurant(id: $restaurantId) {
    ...RestaurantBasicInfo    # reuse same fragment
    menu {
      categories {
        name
        items {
          ...MenuItemFields   # reuse menu item fields
        }
      }
    }
  }
}

# Inline fragment (used for interfaces/unions):
query SearchResults($keyword: String!) {
  search(keyword: $keyword) {
    ... on Restaurant {
      name
      rating
    }
    ... on MenuItem {
      name
      price
    }
    # 'search' returns Union type — inline fragments per possible type
  }
}

# WHY FRAGMENTS:
# 1. DRY: same fields in multiple queries → define once, reuse
# 2. Colocation: component defines its own fragment (React pattern)
# 3. Type safety: fragment '...on Type' ensures fields belong to that type
# 4. Code generation: graphql-codegen generates types per fragment

import org.springframework.boot.test.context.SpringBootTest;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@SpringBootTest
class FragmentTest {
    @Test void fragment_conceptDocumented() {
        System.out.println("GraphQL fragments: reusable field sets, spread with '...'");
        assertTrue(true);
    }
}

# Razorpay Payment GraphQL Schema — Complete

enum PaymentStatus { CREATED AUTHENTICATED AUTHORIZED CAPTURED REFUNDED FAILED }
enum DisputeStatus { OPEN UNDER_REVIEW RESOLVED WON LOST }
enum RefundStatus { PENDING PROCESSED FAILED }

type Payment {
  id: ID!
  amount: Float!
  currency: String!
  status: PaymentStatus!
  merchant: Merchant!
  createdAt: String!
  capturedAt: String
  method: String!             # 'upi', 'card', 'netbanking'
  description: String
  refunds: [Refund!]!
  dispute: Dispute
}

type Merchant {
  id: ID!
  name: String!
  email: String!
  settlementCycle: Int!       # T+n days
  payments(status: PaymentStatus, limit: Int = 20): [Payment!]!
  disputes(status: DisputeStatus): [Dispute!]!
}

type Settlement {
  id: ID!
  amount: Float!
  settledAt: String!
  payments: [Payment!]!
  merchant: Merchant!
}

type Refund {
  id: ID!
  amount: Float!
  status: RefundStatus!
  payment: Payment!
  createdAt: String!
  reason: String
}

type Dispute {
  id: ID!
  amount: Float!
  status: DisputeStatus!
  payment: Payment!
  reason: String!
  respondBy: String!
}

input CreatePaymentInput {
  amount: Float!
  currency: String!
  merchantId: ID!
  method: String!
  description: String
}

input InitiateRefundInput {
  paymentId: ID!
  amount: Float!
  reason: String
}

type Query {
  payment(id: ID!): Payment
  payments(merchantId: ID!, status: PaymentStatus, limit: Int = 20): [Payment!]!
  merchant(id: ID!): Merchant
  disputes(merchantId: ID!, status: DisputeStatus): [Dispute!]!
}

type Mutation {
  createPayment(input: CreatePaymentInput!): Payment!
  initiateRefund(input: InitiateRefundInput!): Refund!
  resolveDispute(disputeId: ID!, resolution: String!): Dispute!
}

# CLIENT QUERIES:

# Query 1: Merchant dashboard widget
query MerchantDashboard($merchantId: ID!) {
  merchant(id: $merchantId) {
    name
    payments(limit: 5) { id amount status createdAt method }
    disputes(status: OPEN) { id amount respondBy }
  }
}

# Query 2: Payment detail page
query PaymentDetail($paymentId: ID!) {
  payment(id: $paymentId) {
    id amount status method createdAt capturedAt
    merchant { name }
    refunds { amount status createdAt }
    dispute { status reason respondBy }
  }
}

# Mutation: initiate refund
mutation RefundPayment($input: InitiateRefundInput!) {
  initiateRefund(input: $input) {
    id amount status createdAt
    payment { id amount status }
  }
}

# GraphQL Custom Scalars

# Built-in scalars: Int, Float, String, Boolean, ID
# Custom scalars: for domain-specific types with validation/format

# 1. DateTime scalar:
scalar DateTime
# Serialization: ISO 8601 string ('2026-05-23T10:30:00+05:30')
# Parsing: validates ISO format, rejects 'yesterday' or '23/05/2026'
# Usage:
type Payment {
  id: ID!
  createdAt: DateTime!    # not String! (validates format)
  capturedAt: DateTime    # nullable DateTime
}

# 2. Rupee scalar (paise for precision):
scalar Rupee
# Stored as Long (amount in paise: ₹1 = 100 paise)
# Serialized: { amount: 500000, formatted: '₹5,000.00' }
# Avoids Float precision issues (0.1 + 0.2 ≠ 0.3 in Float)
# Usage:
type Payment2 {
  id: ID!
  amount: Rupee!          # ₹5000 → stored as 500000 paise
}

# 3. PAN scalar (Indian Permanent Account Number):
scalar PAN
# Format: ABCDE1234F (5 letters, 4 digits, 1 letter)
# Parsing: validates regex [A-Z]{5}[0-9]{4}[A-Z]{1}
# Usage:
type Merchant2 {
  id: ID!
  panNumber: PAN          # nullable: not all merchants have verified PAN
}

# WHEN TO USE CUSTOM SCALAR:
# String: when any string is valid (name, description)
# Custom: when specific format/validation required
#   - DateTime: validates ISO format (not arbitrary string)
#   - Rupee: precision without Float rounding
#   - Email, URL, PAN: format validation at schema level
#   - JSON: pass arbitrary JSON (escape hatch, use sparingly)

# Spring for GraphQL — custom scalar registration:
# @Bean RuntimeWiringConfigurer customScalars() {
#   return builder -> builder
#     .scalar(ExtendedScalars.DateTime)  // graphql-java-extended-scalars
#     .scalar(GraphQLScalarType.newScalar().name('Rupee')
#       .coercing(new RupeeCoercing()).build());
# }

import org.springframework.boot.test.context.SpringBootTest;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@SpringBootTest
class CustomScalarTest {
    @Test void customScalar_useCases() {
        // DateTime: ISO validation, not arbitrary string
        // Rupee: Long paise, no Float precision issues
        // PAN: regex validation at GraphQL layer
        System.out.println("Custom scalars: domain-specific validation at the schema level");
        assertTrue(true);
    }
}

# GraphQL Interfaces and Unions

# INTERFACE: shared fields across multiple types
interface Node {
  id: ID!    # All types implementing Node have an id field
}

interface Priceable {
  price: Float!
  currency: String!
}

# Types implementing interfaces:
type Restaurant implements Node {
  id: ID!
  name: String!
  rating: Float!
  cuisineTypes: [String!]!
  deliveryTime: Int!
  deliveryFee: Float!
}

type MenuItem implements Node & Priceable {
  id: ID!
  name: String!
  price: Float!          # from Priceable
  currency: String!      # from Priceable
  restaurantId: ID!
  vegetarian: Boolean!
  available: Boolean!
}

type DishCategory implements Node {
  id: ID!
  name: String!          # 'Pizza', 'Biryani', 'Sushi'
  restaurantCount: Int!
  imageUrl: String
}

# UNION: multiple possible return types (no shared fields)
union SearchResult = Restaurant | MenuItem | DishCategory

# Alternative: polymorphic feed
union FeedItem = Restaurant | Advertisement | PromoCard

type Query {
  search(keyword: String!, limit: Int = 10): [SearchResult!]!
  node(id: ID!): Node    # fetch any Node by ID (common refetch pattern)
}

# CLIENT QUERY using inline fragments:
query SwiggySearch($keyword: String!) {
  search(keyword: $keyword) {
    # __typename: tells client which type each result is
    __typename
    ... on Restaurant {
      id name rating deliveryTime
    }
    ... on MenuItem {
      id name price vegetarian
    }
    ... on DishCategory {
      id name restaurantCount
    }
  }
}

# INTERFACE vs UNION:
# Interface: types share common fields (Node with id, Priceable with price)
# Union: types have nothing in common, just grouped as possible results
# Use interface when types share fields
# Use union when results are truly heterogeneous

import org.springframework.boot.test.context.SpringBootTest;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@SpringBootTest
class InterfaceUnionTest {
    @Test void interfaceVsUnion_documented() {
        // Interface: shared fields → implement interface
        // Union: heterogeneous results → define union
        System.out.println("Interface: shared fields. Union: heterogeneous types, no shared fields.");
        assertTrue(true);
    }
}

