type Specification {
  key: String!
  value: String!
}

type Category {
  id: ID!
  name: String!
  slug: String!
  parent: Category              # nullable: top-level has no parent
  children: [Category!]!
  productCount: Int!
}

type Seller {
  id: ID!
  name: String!
  rating: Float!
  deliveryDays: Int!
  verified: Boolean!
