}

input ProductSort {
  field: ProductSortField!
  direction: SortDirection!
}

enum ProductSortField { PRICE RATING REVIEW_COUNT NEWEST }
enum SortDirection { ASC DESC }

type Query {
  product(id: ID!): Product
  products(filter: ProductFilter, sort: ProductSort, page: Int = 0, size: Int = 20): ProductPage!
  categories(parentId: ID): [Category!]!
  category(id: ID!): Category
  searchProducts(keyword: String!, filter: ProductFilter, page: Int = 0, size: Int = 20): ProductPage!
  featuredProducts: [Product!]!
}

type Mutation {
  createProduct(name: String!, categoryId: ID!, sellerId: ID!, basePrice: Float!): Product!
  updateProductPrice(productId: ID!, newPrice: Float!): Product!
}

